export const batch138 = {
  'fat-chance.json': {
    base: { id: 'fat-chance', title: 'Fat Chance', author: '', type: 'summary', addedAt: 1781650342055 },
    chapters: [
      {
        title: 'Find the roots of obesity to treat it well',
        text: 'Obesity has spread across the globe, cutting short the lives of millions. Yet fixing it starts with knowing why it happens, how it builds up, and when it takes hold. The where is simple, since it is everywhere, touching every age group. So we need to face it both as a society and as individuals, which means learning how our bodies actually work. The food industry wants us hooked on fast food, so losing weight has never been tougher. How do you stay healthy when supermarket shelves overflow with tempting products? Sugar-heavy diets drive visceral fat, which fuels obesity. Many causes exist, but sugar is the biggest one. Keeping weight off is harder than losing it, and that is the real challenge. Dr. Lustig pushes for a sharp cut to added sugar in everyday products. We are so used to hidden sugar in yogurt, drinks, and bread that we miss it. But it is shaping our health whether we notice or not. If you want to lose weight and eat better, this summary is for you.',
        wordCount: 167
      },
      {
        title: 'Obesity is a rising crisis the world keeps ignoring',
        text: 'Obesity is now a worldwide health problem, growing at a worrying pace. Even with endless media coverage, it is not going away. Most of the food people eat piles on extra fat. Carrying extra weight raises your odds of many illnesses and shortens your life. Obesity is not a death sentence, but research shows only about 20 percent of obese people reach a normal lifespan. A striking 80 percent do not, and that should worry everyone. Being thin does not make you safe from metabolic problems. Many slim people wrongly believe they can eat junk and sugar without consequence. Even thin folks should know that obesity rates are climbing fast. Many who are slim today are at greater risk of becoming obese tomorrow. US health projections suggest that by 2030, around 65 percent of Americans will be obese, up from 55 percent today. Another myth is that a calorie burned equals a calorie eaten, which is not true. Your body controls how it uses energy, and the quality of your calories matters more than the count. Not all fats are equal, so not all calories are equal either. If every calorie were the same, your body would burn fat the same way and fat would not build up. The truth is there are good fats and bad fats, and your body handles them differently. A recent survey of North American men found 42 percent overweight, 34 percent critically obese, and 8 percent at risk of dying from excess weight.',
        wordCount: 247
      },
      {
        title: 'Question the myths about weight and personal choice',
        text: 'Most people blame themselves for being obese, assuming it comes from bad decisions. That belief misses the bigger picture, because many forces drive this global crisis. Obesity is not a personal choice. Obese people struggle to fit into society. They find it harder to date, socialize, and even land jobs. They face more bullying. There is almost no benefit to being obese. So why would anyone choose a life that hurts them socially, romantically, and professionally? Diet and exercise alone rarely work. Dieting and gym routines are seen as the go-to fix, and people buy fast-weight-loss products and sign up at gyms, only to gain it all back when they stop. The root cause is still in their mind, so until that shifts, the weight returns. Obesity is now a pandemic. You are not alone. If it were purely individual, we would not see a worldwide surge. It is a growing crisis shaped by far more than personal choice. People with limited money cannot reach high-quality food. Unlike the wealthy, low-income households often cannot afford fresh goods, so they settle for processed food and sugary drinks. This gap spreads health risks unevenly across social classes. The core problem is that people eat more and move less. Our food carries more fat than we can burn off. There is no single person to blame. Obesity is both personal and a global crisis operating at many levels.',
        wordCount: 241
      },
      {
        title: 'How fast food and weight connect',
        text: 'Is there a link between food addiction and obesity? The answer is not clear-cut, but the two are clearly connected. Many people rely heavily on fast food and soda. McDonald alone serves more than 46 million Americans, showing how demand for processed food keeps climbing. Fast food is full of sugar, fat, and other ingredients that can drive obesity, though the food is not technically addictive. Plenty of people eat fast food without becoming addicted. Even with a clear link, we cannot call food addiction the main cause. The brain craves rewards, and that is what gets you out of bed each day. Without expecting anything in return, life would feel empty. Spices and additives in fast food can make the brain want more, which leads to addiction. Your fat cells work like balloons. Empty cells take up little space. Full cells take up more. Whatever you store in those cells matters a great deal. Insulin is a hormone that controls how your body handles sugar and turns it into fat. You cannot remove a fat cell since it is passed down from your mother. The more weight a woman gains in pregnancy, the higher the chance her baby will be born larger. The best way to shrink a fat cell is to cut off its blood supply, but that is a medical procedure most people cannot access.',
        wordCount: 237
      },
      {
        title: 'The number on the scale is not the whole story',
        text: 'When you step on a scale, it measures four things. Bone is one. Denser bones mean a better chance of a longer life, and they make it easier to stay active in old age. Muscle is another. Muscles absorb glucose and help with insulin sensitivity, and they create energy-burning parts of your body that burn fat well. Subcutaneous fat is the layer many call the big butt fat, and it makes up about 80 percent of body fat. It is actually good for you. Visceral fat is the one to watch. Often called big belly fat, it sits in the abdomen and around the organs, and it offers no health benefit. Visceral fat is the only one of these four that truly threatens your health. Your body needs fat to survive, but when fat lands in the wrong places, it becomes dangerous. Higher weight and high visceral fat raise your risk of dying. Obesity does not kill directly, but it leads to diabetes, cancer, heart disease, high blood pressure, and dementia. These conditions break down your metabolism and shorten your life. There is no pill that can wipe out metabolic syndrome. The most direct way to lower the damage is to limit certain substrates, slow the rate at which your liver processes energy, eat more fiber, and eat more antioxidant-rich foods. Fighting obesity takes consistency. Eat well, move often, and stick to unprocessed food. It is never too late to build a healthier life.',
        wordCount: 252
      },
      {
        title: 'Living well in a high-carb world',
        text: 'Long ago, humans hunted and ate mostly meat and fish, which are low in carbohydrates, and that helped them live long lives. Today, supermarket shelves are packed with processed food loaded with carbs our bodies were not built to handle. To stay healthy, you need to cut your carb intake and eat more vegetables and fruit. Lowering carbs brings several benefits. It improves glucose control, which helps prevent and treat diabetes. Low-carb eating is proven effective for weight loss. Cutting fat and carbs lowers the risk of heart disease. Restricting carbs helps prevent metabolic syndrome. The benefits of carb restriction show up before weight loss even begins. Fructose is another obesity trigger. It is one of the most common sugars and is in nearly every soda and juice. It hits all age groups, which makes it alarming. Fructose drives diabetes by throwing insulin off balance. To keep your carbs in check, you need to cut fructose to the bone. Instead, load up on fiber. Fiber is a powerful tool most people overlook. Your body cannot turn fiber into energy, so it moves through to the bowels, which speeds up digestion and makes it harder to build visceral fat. Fiber also helps regulate insulin, but only when you cut glucose and fructose at the same time. Most people do not realize how little fiber is in their food, and most products barely have any.',
        wordCount: 236
      },
      {
        title: 'A fresh look at exercise and weight loss',
        text: 'Regular exercise does not directly cause weight loss unless you pair it with a healthy diet and mindset. It does make you fitter, healthier, and stronger, and it builds muscle. Moving your body is good for you, but if you want to lose weight, do not count on exercise alone. Exercise boosts health, while dieting shapes weight. Behavior and surroundings matter more than you think. When people change their environment, they step away from old habits that caused weight gain, and that makes it harder to put weight back on. If you exercise for three hours, you will likely skip eating during that time. After working out, you will probably want something light, like fruit, water, or a low-carb meal. Those follow-up choices are what drive weight loss, not the workout by itself. Exercise does not cure obesity, but it gives your body the tools to fight it. Exercise and fiber together form the best defense against obesity. It is better to be heavier and fit than thin and sick. Do not overdo it, since exhausting your body is not healthy. Many people also undervalue vitamin D, which helps fight chronic metabolic problems. Milk is rich in vitamin D, but soda has crowded milk out of diets. Most people today do not get enough vitamin D to support healthy fiber production in their bodies. There is growing concern that some products aimed at babies and kids can drive obesity. These products contain obesogens, from plastic food packaging and cans to toys and shampoos. Obesogens disrupt hormones and are linked to higher obesity rates in young people, which is deeply worrying given how common these products are.',
        wordCount: 269
      },
      {
        title: 'The food industry spreads lies',
        text: 'The food industry pushes a myth that sugar is essential for growth, so we should eat more of it. They claim sugar adds sweetness, stops food from browning, gives texture, and prevents spoilage. Food industry insiders refuse to take responsibility for spreading these myths. They say whatever you eat is your choice, and the ingredient list is always printed on the package. They also argue they only make what people want, which they say justifies the sugar levels. Roughly 80 percent of the 600,000 packaged foods in the US have added sweeteners. The food industry will never give in to pressure to make products healthier, since selling these items is what keeps their business alive. They are partly right, because you must control what you eat, since the industry will not protect you. Some people have genetic conditions that make it nearly impossible to control how much they eat, and for them, the only path is to change their food environment or become a nutrition expert. You decide what goes into your body by choosing what you eat. You can shape your food environment in a few simple ways. Never go to the grocery store hungry. Make a list before you shop and stick to it. Read ingredient lists to know what is really in your food. Skip processed food. Choose unprocessed carbs over refined ones. Build the habit of walking past unhealthy food, even when it is right in front of you. Cook real food at home and add your own spices for flavor.',
        wordCount: 250
      },
      {
        title: 'Taking on the weight crisis',
        text: 'Obesity will not vanish, but we have to push back against the speed at which it is rising. Cutting that number is essential so people do not lose their health early in life. Drug companies are working on new obesity drugs, but politics will slow that down. These companies want repeat customers, so a drug that cured obesity in one round would cost them future sales. The drug industry will keep pushing you to come back for more, because that is how the money flows. Drugs are not always the fix. Mindset is. When people realize they have neglected their health, they tend to make real changes. Improving public health is the strongest tool we have against obesity. People deserve clear information about it. The FDA has the power to test food, evaluate it, and decide what is safe to eat, but the agency is doing too little while the food industry keeps shortening lives. With better public health, people would see the danger in what they eat and reject the food industry excesses. People share blame for their choices, but government bears responsibility too. Politicians are reluctant to fight obesity because the food industry pours money into their campaigns. Every government agency should amplify the call to cut sugar. Better eating means better health. Better health means more productivity and longer life. Raising awareness may feel impossible, but it can be done. Once you understand the danger of obesity, you are one less person on the road to ruin.',
        wordCount: 254
      },
      {
        title: 'Closing thoughts',
        text: 'What you eat and the world around you shape your odds of becoming obese. Obesity is rising fast across the planet, and joining the fight against it is worth your time. Beating obesity is harder than it looks, especially with sugar addiction and high-fat processed food pulling people back. Breaking those habits takes serious commitment and patience. Sugar is a major driver of obesity and needs to be controlled now, not later. Processed food carries its own risks. Many people are living shorter lives because of what they eat, and the worst part is that highly processed food is cheap and easy to find. Government must make a real effort to teach the public about obesity risks, and it must act to slow the rise. The pace at which people are gaining weight demands urgent action. Cutting obesity takes a team effort from the public and from leaders. Healthier people are more productive and live longer. Try this. Eat fruit and other unprocessed food. Cut soda and junk food. Lower your carb intake. Talk to people about the dangers of obesity. Exercise every day. Read it till the end?',
        wordCount: 199
      }
    ]
  },
  'feminine-country.json': {
    base: { id: 'feminine-country', title: 'Feminine Country', author: '', type: 'summary', addedAt: 1781659851243 },
    chapters: [
      {
        title: 'Repaying an old debt',
        text: 'Studying history can trick you into thinking men drove every major event. The truth is that women shaped Ukrainian history in ways that rarely made it into the books. Famous women are exceptions, not the rule. Their work mattered just as much, but men wrote most of what we read. Chroniclers told history from a male viewpoint and left women out. Recently, society has started pushing back against the stereotype of women as the weaker sex, and that means it is time to repay the debt we owe the women who built Ukrainian history and culture. The current generation can tip the scales, give women a leading role in our past and present, and spark real social progress. Women make up more than half of humanity, so a history that ignores them only tells half the story. Repaying that debt is the goal of Feminine Country. The short biographies in this summary are a small slice of the stories of talented and brave Ukrainian women. This collection tries to give them the floor. Each story is about a patriotic, educated, and independent woman who fought for Ukraine alongside men. Above all, this summary challenges the tired idea that a Ukrainian woman is only a mother and housewife. They are far more than that label, and they deserve to be heard. As Vakhtang Kipiani wrote, Ukrainian women were and must be full participants in the historical process, and realizing that means dropping the stereotypes that cloud our view of femininity.',
        wordCount: 234
      },
      {
        title: 'More than a wife',
        text: 'Many outstanding Ukrainian women vanished into the shadow of their husbands, fathers, or sons. One of them is Maria Hrushevska, born Voyakovska, the wife of the famous historian Mykhailo Hrushevsky. But Mykhailo Hrushevsky wife is only one of her many identities. Maria Voyakovska was born on November 8, 1868, in Pidhaychyki, in what is now Ternopil Oblast. Her path to a career in Lviv was harder than her husband ever faced. She lost her parents early and struggled with both money and schooling. Even so, she pushed forward, moving from local schools to a teacher seminary in Lviv. After finishing, she started teaching at a fifth-grade school in the Ternopil area. In September 1893, she joined the First City Women Special School named after Queen Jadwiga in Lviv as a trainee teacher. The move to Lviv opened a new chapter. She joined the cultural life of the city, met writer and activist Natalia Kobrynska and singer Solomiya Krushelnytska, and formed close friendships. Through these connections, she met her future husband, Mykhailo Hrushevsky. They shared a worldview, values, and a love of culture and education. After marrying, Maria did not slip into the role of a quiet housewife. Her marriage actually deepened her interest in politics and society. She stayed a strong supporter of feminism, working with groups that pushed for women emancipation. With Nadia Surovtseva, she brought new life to the National Council of Ukrainian Women and was proud of what they accomplished. She kept working with the Club of Rusyns, the Circle of Ukrainian Girls, and the Shevchenko Scientific Society, supporting her husband career while still pursuing her own path. Many real examples show that women independence does not harm marriage but actually strengthens it. When her husband was exiled, Maria followed and supported him. Later, during the Central Rada, she worked as a full volunteer and assistant, handling paperwork and organizing the work. Her name stayed in her husband shadow, but her contribution to Ukrainian culture, education, and feminism was massive, and her lifelong learning deserves real respect.',
        wordCount: 332
      },
      {
        title: 'The spark of Ukrainian feminism',
        text: 'Maria Hrushevska was not the only feminist in Ukraine. During the interwar period, Ukrainian women built their own movement alongside Western European feminists, but with key differences. Beyond the usual feminist priorities, Ukrainian feminists pushed for women to be part of national liberation and state-building. The Ukrainian feminist movement showed itself most clearly through women associations, communities, and organizations. The most powerful was the Ukrainian Women Union, which worked across Galicia and had around 60,000 members. One of its brightest leaders was Milena Rudnytska, who headed the organization in the 1930s. Milena was a politician and professor who shaped political and social life in Ukraine and abroad. As the leading thinker of the interwar women movement, she argued that the priorities of other countries barely applied to Ukrainian women. The lack of an independent Ukrainian state posed a unique challenge, the feminine identity of the Ukrainian nation. The Ukrainian feminist movement was tightly tied to the nationalist movement and could not stand alone. Ukrainian feminists worked on both women issues and state-building. Ukrainian feminism watched the women movement in Germany grow, but it seemed to be heading the wrong way. Ukrainian women were disturbed by Germany policy toward women and the political use of women groups. Milena Rudnytska openly criticized the German position, pointing out its risks, including the belief that a woman world is limited to family and home. She was convinced that idea did not fit Ukrainian society, which needed women contributions as much as men. For her, gender equality meant equal activity in civic life. As she put it, equality was only the door to public life as a co-shaping and co-responsible force, one that allows us to reshape the world men have built.',
        wordCount: 283
      },
      {
        title: 'Kindness above all',
        text: 'Among hundreds of biographies, Olena Viter story stands out. She had a strong sense of justice and unshakable faith in kindness. She was born in 1904 in the Lviv region to a family that taught her to love the Motherland. Olena studied at a medical institute, but her life changed dramatically after her father died. She left school and entered a monastery. Becoming a nun was not a way to escape reality. She stayed an active public figure and kept practicing medicine. In the summer of 1930, Olena joined the Organization of Ukrainian Nationalists, which fought for Ukrainian independence during Soviet repression. She started teaching adults and children at the monastery, and in 1932, she became the abbess of the monastery, which let her keep doing scholarly work. The heart of feminism is that there are many ways of being a woman. Everyone has the right to choose their path, and all paths are equal. Peace ended in 1939 when Soviet forces took western Ukraine. The Red Army destroyed her monastery, but she kept working in secret. During the occupation, she stayed in touch with the OUN, helped refugees cross the border, restored children education, and supported the liberation struggle. In 1940, the NKVD arrested her for helping the OUN. The investigation lasted six months, and her life was a nightmare. She endured daily torture and humiliation, but 47 brutal interrogations did not break her greatest gift, her innate kindness. She miraculously escaped the death penalty and went back to her usual work when she was freed. She restored the monastery and opened new schools. The revived monastery became a refuge for those hunted by the new German government, and she helped Ukrainian politicians and Jewish people escape the Nazi regime. The return of Soviet power brought new challenges. The NKVD kept hunting anyone who opposed the regime. In 1945, she was arrested again and sentenced to 20 years of hard labor on falsified charges. After ten years in exile, the NKVD reviewed her case and released her early. Once again, she went straight back to her life work. She restored another monastery and served underground in the Ternopil region, where she spent her last 32 years. Much of what happened in those years is lost, but her self-sacrificing spirit clearly shaped the path she walked.',
        wordCount: 360
      },
      {
        title: 'A voice for the deported people',
        text: 'Ayshe Seitmuratova is another name you rarely see in history books. She was born in 1937 in Crimea, then one of the autonomous republics of the Soviet Union. Her father joined the Red Army in 1941, and German troops captured the village where her family lived at the start of the war. In 1944, when Soviet forces came back to Crimea, her life changed overnight. Her family was woken in the middle of the night, told to grab only the essentials, and forced out of their home. The deportation of the Crimean Tatars from May 18 to 21, 1944, was genocide. Around 423,100 Crimean Tatars were deported, and between 27 and 46 percent died within the first year. Most deportees were sent to Uzbekistan and Kazakhstan, with some going to remote Russian regions. Ayshe family ended up in Uzbekistan, where they worked hard just to survive. When their situation improved, Ayshe returned to school and enrolled at the Uzbek National University in the Faculty of History. The early memories of Soviet brutality and deportation stayed with her and shaped her worldview. She joined the national movement for the return to Crimea, gathering information about deported Crimeans, their discrimination, and their suffering. Ayshe was arrested twice and accused of opposing Soviet authorities, but threats and punishment could not stop her fight for justice. After her second arrest, she was sentenced to three years in prison. In the mid-1970s, facing yet another arrest, she made the hard choice to emigrate to the West. Free from Soviet surveillance, she could help her people more actively. At 42, Ayshe started a new life in the US. She learned English and began working with radio stations like Freedom and Voice of America, telling the world about her people plight. During ten years in exile, she did remarkable work, attending international conferences and forums. She became a strong and steady voice for deported Crimeans. Her biggest achievements included a speech to the US Senate, a meeting with President Reagan, and addresses to the parliaments of Canada, Great Britain, and Italy. In 1992, Ayshe returned to her native Crimea as a national heroine and threw herself back into work. She founded the House of Kindness charity to support Crimean Tatars and created a boarding house for older people. She still lives in Crimea and believes Crimean Tatars should build their statehood alongside the Ukrainian people, because that is the path to real prosperity.',
        wordCount: 352
      },
      {
        title: 'Women on the cultural front',
        text: 'Ukrainian women have shone most brightly in culture, where their creative work almost always blends with activism and the fight to preserve national identity. Olena Teliha, a Ukrainian poet and writer, is a great example. She spent her early childhood in St. Petersburg and did not speak Ukrainian, even though her roots were fully Ukrainian. When she was ten, her family moved to Kyiv, where she saw the revolution and witnessed the birth of an independent Ukrainian state for the first time in the 20th century. She fell in love with the Ukrainian language and culture. When the Bolsheviks took Kyiv, being forced into exile in Czechoslovakia was devastating. In Prague, Olena met Ukrainian intellectuals and her future husband, UPR army officer Mykhailo Teliha. While studying at the University of Prague, she wrote her first poems and became a regular contributor to the Literary and Scientific Bulletin. Later, she joined the OUN, where she handled hard but vital tasks. She wrote texts for leaflets and propaganda and created educational materials. Working with the OUN, she kept her creativity alive and found ways to support Ukrainian culture in such dark times. In 1941, Olena returned to Ukraine and took on cultural and educational work, including leading the Union of Ukrainian Writers. Any national liberation struggle needs equal effort from women and men. In 1942, Olena was arrested for crimes against Soviet authorities and shot in Babyn Yar. Her life ended in tragedy, but she left a real mark on Ukrainian literature and the liberation struggle. Kvitka Cisyk is another bright name in Ukrainian culture, the most outstanding and influential Ukrainian singer. Though born in the US, Cisyk was Ukrainian at heart. Most of her family came from the Lviv region and never forgot their roots. She grew up convinced she should help her distant Motherland. What could she do? The answer was her deep love of Ukrainian songs and music. With a stunning voice, she learned Ukrainian folk songs from her grandmother and mother. As an adult, she knew her calling was to sing Ukrainian songs and make sure the world heard them. During her tragically short life, she recorded three studio albums of Ukrainian songs that gained wide popularity. Her unique voice and original melodies won the hearts of listeners, and she reached the souls of millions. One of her Ukrainian-language albums was nominated for a Grammy Award in 1990.',
        wordCount: 379
      },
      {
        title: 'Closing thoughts',
        text: 'The history of Ukraine and its culture is full of amazing women whose stories stir every emotion, from pride to deep sadness. All Ukrainians should talk about them, honor their achievements, and show gratitude for what they gave the country past, present, and future. The list of outstanding Ukrainian women in science, education, culture, and politics is far longer than the few names in this summary, but their stories reveal the real power of Ukrainian women. They show that past pages hide a great deal, including how much female courage and sacrifice sit between the lines and how many famous names we have forgotten. We must piece this history back together and show it to the world. Hopefully, this short review moves you to learn the stories of outstanding Ukrainian women so you understand them better. Learning about their experiences can change how we see historical events and eras. Without women contributions, the story of the Ukrainian state would look completely different, and we should remember and honor each of them. After all, Ukraine is of the feminine gender. Try this. When you study history, look for the female perspective on the event. That viewpoint is rarely the center, but it can reveal many more details. Read it till the end?',
        wordCount: 226
      }
    ]
  },
  'find-your-artistic-voice.json': {
    base: { id: 'find-your-artistic-voice', title: 'Find Your Artistic Voice', author: '', type: 'summary', addedAt: 1781659944540 },
    chapters: [
      {
        title: 'Being different is an artist superpower',
        text: 'Everyone likes to blend in sometimes and go unnoticed, but every time you speak up, you sharpen your voice. That voice decides your value as a creator in the art world. Being different is scary, confusing, and shakes your confidence. The first reaction is often to hide what sets you apart, but the better move is to lean into it. Finding your voice is a long road of vulnerability, risky attempts to put your ideas out there, and failure. It means having the courage to stand by your vision and your own definition of it. This will be one of the most important experiences in your life. Still, do not treat finding your artistic voice as the final goal. Your voice is a living part of your art, and it stays flexible and evolving as long as you are alive and making things. The art world elite rarely talks openly about finding a creative identity. Despite how important it is, the topic stays mysterious. There is no clear formula for finding yourself in creativity. For every artist, the path is intuitive and original. The downside is that you walk it alone, but the upside is total freedom. Artistic development happens not because of outside influences but in spite of them. As a person of art, you soak up every form of it and notice other people creations everywhere. In your search for originality, you probably worry about accidentally copying someone else or getting lost in a crowd of artists following the same movement. Do not worry. There are ways to ease those fears and grow stronger on your creative journey, and you will see them right now.',
        wordCount: 257
      },
      {
        title: 'No one else can sound like you',
        text: 'Your artistic voice reflects who you are. It carries the marks of your life experiences, values, interests, fears, and beliefs. It shows how you meet life and share your unique view of the world, for example the idea that pink suggests joy, that sunlight makes everything more beautiful, and that everyone feels lonely sometimes. Making art is a deeply personal experience, as artist Liza Congdon has said. Anything you once thought mattered will find a place in shaping your creative identity. With enough courage, you will pour your story into it, including your deepest pain and your hope. That becomes your artistic theme. Its parts include your education, homeland and ethnicity, sexual orientation and preferences, political and civic stance, and religion and superstition. Theme, style, and craftsmanship together form the integrity of your artistic identity. Note that creative voice is not the same as style. Style is just the outer shell of your creativity, and it includes lines, forms, layers, colors, textures, patterns, and images. At the same time, an artist does not have to stick to one style. Still, an attentive audience can always trace the creator particular voice in how those style elements come together. Craftsmanship sharpens the depth and precision of your expression. It bridges the gap between what you imagine and what you can actually create. Steady practice gives you the finesse to express your ideas as close to the mental image as possible. Being a master means having every technical tool and skill to translate your concepts. That does not mean you will never create weak work, since an experienced artist risky experiments are signs of ongoing growth. An artist voice is not final or fixed. It grows through consistent work and keeps putting out new shoots. A creator is sensitive to inspiration and follows it, even when it leads somewhere unusual. Expanding your voice is like orbiting your ideas, themes, skills, and style. You keep moving without ever leaving the main path. Art is a mirror of your inner self. Setting your voice means showing the world what your eyes see and your soul feels. Artists struggle to pull their feelings and thoughts out of the general noise of outside influences. Later, you will find some practical tips to handle that, so stay tuned.',
        wordCount: 326
      },
      {
        title: 'Finding your voice is a path of self-discovery',
        text: 'Many artists wrongly believe their own lives are not interesting or worth noting. That view changes once they start creating. A standout feature of creativity is that it lets the artist discover and share their inner world. Art teaches the creator to look closely at the soul and treasure the gems found there. You may think your story is less attractive, bright, or dramatic than others, but do not give in to that fear. There is always a moment to share your vision, and it will find its audience. Here is a useful tip. Make your self-doubt part of the story and express it through art. It helps you push past your inhibitions and gives moral support to others who are afraid to put themselves out there. Finding your artistic voice takes you deep into yourself, and creativity is one of the best tools for reflection, introspection, and even therapy. The good news is that everyone has a unique voice. It hums inside you like a quiet melody, waiting for you to hear it and turn up the volume so others can tune in. No one can take your voice away, but it is also true that once you recognize it, it is yours forever, undeniable and inescapable, even when you try to ignore it. Honest self-expression takes real mental and emotional effort. Your art can and should reflect your mental state. Do not protect your creativity from sadness, fear, or anxiety. Instead, let those feelings live on your canvases and let them drift away. Feel free to share your struggles with your audience. People crave honesty from creators because it mirrors their own experience. Staying true to your artistic vision in a world that often chases instant gratification is tough. It is tempting to chase likes, trends, and short-term fame. But those things are shallow and fleeting. Chasing fashion keeps you from building the foundation of your artistic identity, especially early in your journey. Pay attention to your feelings and protect yourself from the harmful pull of social media. Notice when you start comparing yourself to others or getting tense, and then take a break. Occasional digital detoxes help lower anxiety and keep your voice distinct from the millions of others out there.',
        wordCount: 351
      },
      {
        title: 'You will not succeed the first time, so try again',
        text: 'You will certainly have days when you do not want to pick up a brush. Maybe you will often feel that you have more reasons not to paint. Your motivation will not always be there, which is why discipline matters. Build a habit of daily practice. The goal is the process, not the final product. Roughly speaking, an hour of painting you crumple and toss is just as successful as one that ends with a finished piece. Either way, that hour moves you closer to finding your artistic voice. Allow yourself to throw out canvases without guilt. Of course, you cannot know in advance whether your work will resonate with others, and some pieces may never get noticed. That is no reason to hold back. Express yourself despite the fear, or you will lose the chance to someday be a favorite with your audience. Lost chances hurt a creator far more than failures do. Rejection stings, but every great artist has faced it. It is part of the road to your artistic identity. Accept that no one will hand it to you on a silver platter. You shape and refine it through mental, spiritual, and practical work. You reach your potential only as far as you let yourself become anything at all. Do not expect to stay in a state of inspired bliss. All creative people go through cycles of highs and lows. Hold on to that thought when you feel stuck and worried your vision will not clear. Every time you hit the bottom of a creative block, remind yourself that a new high is close. Mood swings come with any creative profession, so think of them as the price of the joy of inspired creation. The irony is that feeling uncomfortable almost always means you are doing something right. Do not aim to make only masterpieces. Let dozens of paintings go to the trash so that a few can blend all your best effort into something whole.',
        wordCount: 308
      },
      {
        title: 'Keep the creative fire alive',
        text: 'The urge to create always starts with a spark. It might be a movie, a song, a stunning landscape, or a first crush. Whatever it is, it is the first push for creativity, born in your soul. In that moment, you feel a bond with art, the world, and every creator who came before or lives now. Creation draws new artists in with the promise of a joyful union. Art is one of the ways to beat existential loneliness. Sadly, not everyone follows that first impulse. For some, the spark smolders for years, and others never pick it up because of prejudice, social pressure, family rules, or judgment. Especially damaging is the stereotype that art is only for the gifted. As you can see, many forces try to smother the urge to express yourself. On top of that, the search itself can bruise your ego, so be proud of your courage if you decide to go for it. The most successful creators push past common thoughts like it is not time yet, I am not ready, and someday later, when the moment is right. The greatest artists in history took the risk of starting to realize their ideas right away, even without every tool. Experimentation is where creativity comes alive, as Lisa Congdon has noted. The hidden mental trap is the idea that doing anything you are not good at is uncomfortable and embarrassing. You picture the result matching your refined taste, but you have not built the skills yet, so you feel defeated. In uncertain moments, the boldest artists decide to experiment, and that is where the original authentic voice is born. Each experiment can produce unexpected results that fuel your creative growth. Set aside time each day for free creativity. You may think you only have half an hour between work and chores, but that time is better spent painting than scrolling through social media. Make a schedule and stick to it. Treat it like a rehearsal before the high-paying commissions of your future clients.',
        wordCount: 313
      },
      {
        title: 'The artist path is never smooth',
        text: 'A creative block can be useful if you do not run from it but lean in. Of course, you want to hide from uncomfortable feelings, but a more productive move is to look at them closely and try to understand what they are telling you. If you sit with your doubts, they will help you grow. As a result, you will move into a new stage of your creative path. Anxiety about your work may point to deeper issues that need attention. Maybe it is a sign of something like impostor syndrome or an old unconscious resentment. To work through a creative crisis, consider these three strategies. First, understand and address the cause. Explore what is triggering the block. Keep a personal diary to sharpen the main questions for yourself. Ask who owns the critical voice in my head, whether there is any real evidence for its claims, and why you hold negative beliefs about yourself. Write down your stream of thoughts and reread them. You will gain insights that bring relief. Second, take a break and try other activities. This is especially relevant for creative burnout. No matter how much you love your craft, your mind needs rest and a change of pace. When your art starts to annoy you, step away from it for at least a week. Fill those days with other living experiences. Take walks, go to nature, visit museums and theaters, watch movies, and read the books you have been putting off. Third, draw inspiration from what you love. Focus on your interests and create a family tree of your creative voice, with branches dedicated to your sources of inspiration. They might include vintage clothes from your great-grandmother chest, the history of photography, and French literature. When you feel stuck, turn to this imaginary tree and pick ideas from its branches. You will come out of the crisis with new energy and enthusiasm. Do not fear stepping out of the flow. It is not a disaster but a chance to deepen your creative experience. Imposter syndrome is a psychological condition in which people credit their accomplishments to luck, chance, or injustice. They unreasonably believe they reached their position through deceit, not effort.',
        wordCount: 333
      },
      {
        title: 'Closing thoughts',
        text: 'Every professional was once a beginner who dared to ruin a clean sheet. That thought should bring hope to creators still at the start. Even your idols, the best in their craft, were once amateurs. It is tempting to assume everything came easily for them on the first try, but that is a lie. Every great artist has walked their own road, full of self-doubt and the urge to quit. They all felt confused and clumsy at some point. Even skilled professionals still face crises and react sharply to criticism. There is no point at which the creator is bulletproof. Creation is always hard, but how you respond depends on your courage. Stepping out of your comfort zone will cost you, so be ready to admit your mistakes, take feedback, and stay open even when you feel like giving up and hiding. If you follow through, you will find your unique artistic voice and reach the people who need it. They will see themselves in your work and find comfort and inspiration. People of every language will understand your creative voice, and you will be able to bring them together through the feeling you express. That is real magic. Take this path. Try this. Practice the beginner mindset. Face challenges with an open mind and without the bias of your experience. Be naive. Build a supportive and creative community. No one will understand you like other artists going through the same thing. Surround yourself with friends with whom you can swap the role of teacher and student. Get into the habit of writing down all your ideas and keeping an endless list of inspiring things. Use it when you brainstorm. Read it till the end?',
        wordCount: 281
      }
    ]
  },
  'fluke-chance-chaos-and-why-everything-we-do-matters.json': {
    base: { id: 'fluke-chance-chaos-and-why-everything-we-do-matters', title: 'Fluke', author: '', type: 'summary', addedAt: 1781658592934 },
    chapters: [
      {
        title: 'A hidden force in human history',
        text: 'What if your vacation could reshape thousands of lives? That is not a superhero plot. It is the real story of Henry L. Stimson. In 1926, he and his wife spent six days in Kyoto, Japan, walking through temples and gardens. The Japanese felt the consequences of that visit almost twenty years later. By then, Stimson was the US Secretary of War. As a civilian executive, he stayed out of most high-level decisions. Yet, when he saw the list of atomic bomb targets, which included Kyoto, Hiroshima, Yokohama, and Kokura, he stepped in to save the city he had visited. It was not easy. The generals wanted the bomb to end the Pacific war, and Kyoto fit the bill as a wartime industrial center and former capital. Still, Stimson persuaded President Harry S. Truman to drop Kyoto from the list. They added Nagasaki instead. Sometimes the most important events are the ones that never happened. Stimson trip to Kyoto rarely makes it into history books, since the coincidence feels unusual. Yet randomness is far more common and important than most people realize. Step into this eye-opening journey through mind-blowing flukes and learn how to make peace with uncertainty.',
        wordCount: 192
      },
      {
        title: 'Flukes and where to find them',
        text: 'Big events should have big causes, right? That is what Brian Klaas thought a few years ago when he went to Zambia to investigate a failed takeover. Was it because citizens did not back the rebels, or was the system too stable for a coup? Klaas wondered. The real reason happened in seconds, when the army commander ran from rebels who tried to kidnap him. Time flukes are everywhere, and our existence as a species depends on them. If that famous asteroid had arrived a minute later, it would not have hit Earth 66 million years ago, dinosaurs would have kept ruling, and humans would never have had a chance to appear. The lottery of the earth is another fluke. Saudi Arabia discovered its oil in 1938, when it was a low-income country built on farming and herding. Today, Saudi Arabia is one of the richest nations on earth. Many factors shape your wins and losses, not just your actions. We do not need to travel far to see flukes in action. One of the most amazing ones sits inside our cells, the mitochondrion. This powerhouse came from the merger of a bacterium and a prokaryotic cell that had no organelles. Over time, the bacterium became a mitochondrion and started supplying cells with energy. Every complex species owes its existence to that merger. A random event does not have to be complex to have a big impact. Weather unpredictability is a clear example. Edward Norton Lorenz showed that tiny changes, like a one-millionth of a degree temperature shift, can shape the weather. That finding gave rise to the butterfly effect, the idea that small local changes, like a butterfly flapping its wings, can produce major effects far away. On August 9, 1945, Kokura weather broke from the forecast of clear skies. Clouds covered the city, so the US pilot gave up on bombing it. Over Nagasaki, the clouds cleared at the last moment, sealing the city fate. The Japanese later coined the phrase Kokura luck for people who narrowly escape disaster. Our eyes evolved from a fluke, a random mutation that created light-sensitive cells.',
        wordCount: 296
      },
      {
        title: 'One person, massive impact',
        text: 'Social factors also shape the fate of humanity. For instance, if Nikita Khrushchev had been ill-tempered, the Cuban Missile Crisis could have ended very differently. Sometimes, even subtler details tip the scales. Most people have heard of Charles Darwin discovery of natural selection, the idea of the survival of the fittest. This idea changed science, but it almost never surfaced because of a quirky belief. As he prepared HMS Beagle for its next voyage, Captain Robert FitzRoy wanted an educated companion to ease his boredom at sea. A friend suggested Charles Darwin, but FitzRoy hesitated. Why? The shape of Darwin nose. The captain believed in physiognomy, the idea that physical features reveal character. FitzRoy thought Darwin nose suggested he would not survive the hardships of the voyage. Luckily, FitzRoy agreed to take the young naturalist aboard, which let Darwin collect the samples that led to his famous discovery. As John Muir wrote, when we try to pick out anything by itself, we find it hitched to everything else in the universe. You do not need a high position or a famous name to make a real impact in an interconnected world. Consider these two stories. In 2001, Elaine Greenberg was heading to meet her colleague Joseph Lott at a conference in New York City. Knowing he loved impressionism, she bought him a tie covered in Monet paintings. She gave it to him just before the conference. Deeply moved, Lott wanted to wear it right away, but Greenberg said, not with this shirt. Even though it would make him late, Lott went back to his hotel to change. That decision saved his life. It was September 11, and the conference was in the World Trade Center. Another story happened to a tourist named Ivan in 2022. While swimming near the Greek coast, he was swept out to sea. After 18 hours of searching, the coast guard gave up hope. Yet Ivan was found alive. He had spotted a soccer ball in the water, held on to it, and survived. When the story made the news, a woman recognized the ball. Her children had lost it while playing by the sea. Treat unplanned events with patience, because you never know when one might save a life.',
        wordCount: 334
      },
      {
        title: 'Is ignoring randomness a wise move?',
        text: 'If flukes keep shaping human history, why do we hardly consider them? A few reasons explain this. First, we are pattern-creating creatures, so the word accidental rarely comes up. In one experiment, American psychologists showed people simple animations of shapes of different sizes moving around the screen at random. Most participants saw it as a story about a big triangle hunting other figures. Biologically, patterns and stories helped us survive. When our ancestors heard a noise, they quickly linked it to a predator. Legends shared around the fire passed wisdom to the next generation. The Moken are a vivid example. On December 26, 2004, the Indian Ocean tsunami struck huge coastal populations and caused heartbreaking damage. Yet every Moken person in Thailand survived. From childhood, they knew the legend of the laboon, giant waves whose approach silenced the cicadas. When they noticed the silence on December 26, the Moken quickly evacuated. Patterns and stories make our lives feel more ordered and certain, which makes flukes seem like oddities. Second, the Enlightenment period strengthened our faith in order. For a long time, researchers acknowledged the importance of both convergence, or regularity, and contingency, or randomness. Yet when Isaac Newton, one of the fathers of the Enlightenment, discovered the laws of gravity and motion, convergence ruled. It seemed like physics could explain everything, leaving no room for randomness. The Enlightenment also introduced reductionism, the idea that we can understand the whole by studying its parts. This works for complicated systems like a Swiss watch, but applying it to complex systems like society, where every part shapes the others, leads to mistakes. Convergence-centered thinking has created long-lasting misconceptions, like the belief that events usually have one cause, that big causes drive big events, and that cause and effect are simple. In fact, events can be random or driven by many causes that mix in different ways. Small changes, like temperature shifts, can decide the fate of entire cities. As Brian Klaas wrote, rather than rewarding intellectual humility, we too often confuse false certainty with confidence and power. If we leave randomness out of the picture, our view of reality gets distorted. In an interconnected world, that can have dire consequences.',
        wordCount: 309
      },
      {
        title: 'Why the world grows more unstable',
        text: 'If the Enlightenment picture of reality is incomplete, what is closer to the truth? Our world is a place where convergence and contingency sit on equal footing, and every action matters. It looks like what Argentine writer Jorge Luis Borges described in The Garden of Forking Paths. When a person does something, the number of paths available to them changes. Reality is even more layered. Our actions, other people actions, natural forces, and many other factors shape the paths that unfold before us. Often, stuff happens is the most honest explanation of what is going on. Today, humanity faces powerful random events more often than in the past. Why? Self-organized criticality describes our situation well. Each event adds to the previous ones, leaving a moderate effect. Then, when a critical point is reached, one change can undermine the whole system and become a high-impact black swan event. If earlier events needed decades to push toward a tipping point, today they need far less time, because of four factors. Globalization means that being closely interconnected raises the risk of global instability. If something big happened in one region in the 1800s, other parts of the world barely felt it. Today, a crisis anywhere influences most of the world. When a ship crashed into a bank of the Suez Canal in 2021, huge amounts of international trade suffered. The internet gives destructive ideas a powerful tool to spread, and prompting destabilizing actions has never been easier. Optimization has pushed systems to their limits, leaving no room for flexibility. A country energy system should be unified for top efficiency, but if something breaks in one region, power cuts ripple across the country. Speed has increased, and many processes unfold much faster than before. Scientists are still working out when an all-changing action occurs, but they have already spotted a red flag, critical slowing down. Stable systems recover from tiny disturbances quickly, but systems approaching instability take far longer to bounce back. The good news is that we can use this knowledge to our advantage.',
        wordCount: 305
      },
      {
        title: 'The upside of uncertainty',
        text: 'Knowing that random events can change our lives dramatically should not make us feel helpless. In a world where coincidences play a decisive role, every action matters. For example, our existence comes from countless flukes across history. If just one ancestor had behaved differently, we would not be here. By the same token, if we were not who we are, many lives would look different. Social media often shows these links, since our posts can reach people in distant corners of the world and improve their lives. Sadly, we often do not know the impact of our actions. But just being aware of our influence is valuable. It keeps us from feeling like a cog in a machine and softens some of the harshest effects of individualism. Self-reliance has many benefits, like pushing us to act rather than only react. But individualism carries two downsides. Loosening our tie to community can weaken what gives life meaning, while seeing ourselves as part of a whole adds meaning. The idea that we are solely responsible for our lives implies we should control what we cannot, and since we cannot, we should stop blaming ourselves when life does not go as we wish. Does accepting randomness mean we should give up? Not at all. We should keep being proactive, but aim for resilience, not efficiency. Building flexibility is one of the most important ways to do that. What does it look like? On a personal level, a checklist lifestyle lets us do more, but it leaves almost no time for experimentation. Yet those activities matter as much as serious tasks. In an uncertain world, it is wise to avoid putting all eggs in one basket and instead keep a few backup plans we discover through exploration. Switching our mind off tasks also gives us room for leisure. On a societal level, instead of funding only the scientists who promise results, authorities and investors should support prominent researchers from many fields, since we never know what topic will matter most tomorrow. A world full of flukes means miracles wait at every corner.',
        wordCount: 308
      },
      {
        title: 'Closing thoughts',
        text: 'Thinking that everything happens for a reason may make us more confident, but it does not match reality. Random events shape our lives every day, whether we want them to or not. So instead of running from uncertainty, we should face it. Reforms in social science can help. If we pay more attention to outliers in data and to fruitless experiments, our view of ourselves will sharpen. I don know should become a valid answer on its own. It is better to pause and explore different paths than to march confidently in the wrong direction. Try this. Schedule 30 minutes a day for exploration. Listen online to The Köln Concert by Keith Jarrett. This jazz classic came from a fluke, since Jarrett had to use all his creativity to hide that the piano was broken. Read The Garden of Forking Paths by Jorge Luis Borges. Read it till the end?',
        wordCount: 154
      }
    ]
  },
  'food-fix-how-to-save-our-health-our-economy-our-communities-and-our-planet.json': {
    base: { id: 'food-fix-how-to-save-our-health-our-economy-our-communities-and-our-planet', title: 'Food Fix', author: '', type: 'summary', addedAt: 1781650544148 },
    chapters: [
      {
        title: 'Food choices shape your body and mind',
        text: 'In 2018, nutritionists were puzzled. Research showed that almost half of Thai Buddhist monks were overweight and 10 percent had diabetes. How could that be? They stuck to tradition and fasted daily, so their meals had far fewer calories than the average Thai citizen. After watching what they actually ate, scientists found the cause. The monks indulged in soft drinks. We often focus on the number of calories, but the quality of those calories matters just as much. The 100 calories from sugar and fat affect the body differently, since sugar slows metabolism while fat does the opposite. As Dr. Mark Hyman has written, calories are information, instructions that affect hormones, brain chemistry, the immune system, the microbiome, gene expression, and metabolism. Despite eating a lot, more than 90 percent of Americans lack essential vitamins. What we have in excess are unhealthy additives, with each person consuming 3 to 5 pounds a year. As a result, we are more prone to chronic disease. Not all food harms us. Scientists in Philadelphia found that after serving patients nutritious meals for a year, hospital visits dropped by 50 percent, and when patients did come in, they spent 30 percent less time in the medical center. Carefully chosen food can be medicine. Healthy eating sounds simple in theory but is hard to put into practice. Food quality comes from economic, political, ecological, and social factors, and we have to tackle all of them if we want to live longer. Are you ready to discover the hidden truth about what you eat? A warning, it may shock you.',
        wordCount: 254
      },
      {
        title: 'Unhealthy products are symptoms, the system is the cause',
        text: 'Have you ever wondered about the life story of a hamburger on your plate? It might be eye-opening. Until 1990, countless small seed companies existed, and their products added to species diversity and resilience. Over time, more than 100 of them ended up in the hands of four large corporations. Today, these corporations supply over 60 percent of seeds to farmers and sell the pesticides and herbicides used to protect the crops. Glyphosate is among the most popular, with Americans using more than 3.5 billion pounds of it on over 70 crops each year. That means you can find glyphosate in nearly everything, from bread to a sushi roll. Studies have shown that even 0.1 parts per billion can harm the microbiome. Less than 5 percent of American farmland grows fruits and vegetables. As the soil wears out, farmers add more chemicals, which may also come with the water used for irrigation. Crops soak up these toxic ingredients, so the bun on your hamburger is far from a healthy choice. The same pattern plays out on animal farms. Overcrowded and unsanitary conditions trigger disease, so workers add antibiotics to feed to keep cattle alive and growing. As a result, the meat carries drugs and chemicals. But that is not the end of the journey. Once it reaches kitchens, chefs add more additives and flavor enhancers before it lands on your plate at the cafe. Not every hamburger starts this way, but it is typical of many dishes. Why are we unaware? Some companies work hard to keep us in the dark. This story is a telling example that our food system is broken. Today it looks like a vicious cycle, with farmers and consumers trapped inside. Without government support, farmers often have no choice but to use pesticides, or they face bankruptcy. More herbicides mean worse soil, which means more chemicals the next season. Consumers unintentionally keep this model alive, since many people cannot afford organic produce. They pick the cheaper option and pay for it with their health. The first step in fighting this unfair system is seeing the link between politics, agriculture, and the environment, because food touches all three.',
        wordCount: 322
      },
      {
        title: 'Practical ways to limit chemicals in your diet',
        text: 'Ultra-processed food is gaining popularity from Mexico to India, slowly replacing traditional diets, and in the US it now makes up almost two-thirds of our calories. The consequences are dramatic. In 1962, 3.4 percent of Americans were obese, and today that number is 40 percent. About half of Americans have pre-diabetes or type 2 diabetes, and even teenagers are affected, numbers that would have seemed unthinkable 30 years ago. The trend is global, and the situation is worse in some countries. In the 1990s, 1 in 150 Chinese had diabetes, and by 2030, that figure is expected to reach 1 in 10. As Dr. Mark Hyman has noted, your zip code is a bigger determinant of your health outcomes than your genetic code. So it is time to take control of what we eat. Follow these recommendations to improve your well-being. Eat up to fifteen servings of whole plants each day, choosing low-glycemic fruits like apples, cherries, grapefruits, and blackberries, and add whole grains to your plate. Make healthy fats a habit, starting with nuts and seeds, which lower disease risk, and add meat only if you can find a free-range farm that avoids chemicals. Eggs are also a good choice since they are packed with nutrients. Pick fish low in mercury, like herring and sardines, which are full of omega-3. Do not overlook the mineral and protein content of beans. Cut back on sugar in food and drinks, including juices, since studies show that one soda a day raises the risk of diabetes by more than 30 percent. Be careful with cow dairy and try goat or sheep options instead. Visit the Non-GMO Project website, an initiative that checks products and lists sellers who avoid GMOs, with a database of over 14,200 retailers. Read food labels and skip products with words you cannot understand, such as potassium bromate (E924), azodicarbonamide (ADA), BHA, BHT, brominated vegetable oil (BVO), yellow food dyes number 5 and 6, and red dye number 40, all of which carry serious risks. Limit plastic containers, since their chemicals can leach into food. Support small local farmers and people who push for organic food, using the LocalHarvest database to find them.',
        wordCount: 322
      },
      {
        title: 'Why school lunches need an upgrade',
        text: 'Obesity rates have shot up over the last 50 years, and today, one in three children struggles with weight. A sedentary lifestyle is not the only reason. Look at school meals and ask why they are full of junk food. First, nutrition standards for school lunches are full of loopholes. They count ketchup, tomato paste, and french fries as vegetables. A Smart Snacks policy allows companies to sell junk food as long as the label says whole grain or reduced fat. Some schools have even negotiated with Domino Pizza about sales. Second, massive advertising is a culprit. Ads are everywhere, from TV to buses to schools, but the most dangerous space is digital. Marketers place ads in websites, movies, and videos. For example, Pokémon GO sent its players to McDonald because the company sponsored the game. Shockingly, this restaurant chain and Coca-Cola target even two-year-old children in their ads. In 2016, 56 companies paid for 3.4 billion promotional posts on social media, and they do it to build lifelong customers. A 30-second ad is enough for kids to choose that brand later, and if the ad repeats, they become devoted fans. Some cases show how we can tackle this challenge. Many Boston public schools had no kitchens, only microwaves, so they bought meals in plastic containers and heated them up. Businesswoman Jill Shah decided to change that and built the Hub and Spoke model, where schools with cooking equipment prepare food for the ones that lack it, which made meals healthier and created jobs. The Wellness in the Schools initiative is changing menus for pupils. In New York, culinary graduates work in school kitchens for three years, setting new cooking standards and teaching others. Another public-private partnership, Salad Bars to Schools, supplies schools with fresh vegetables. In Sweden, toy and junk food ads can target children only over 12, and any ad aimed at younger kids is illegal. There is more we can do in schools. Remove junk food and replace chocolate milk with white milk to cut sugar. Search for local organic farms. Organize a garden nearby. Add cooking skills and basic nutrition knowledge to the school program.',
        wordCount: 339
      },
      {
        title: 'Healthy food should be within everyone reach',
        text: 'In 2018, researchers spotted a telling pattern. In poor districts near New York, ads for unhealthy drinks appear two to four times more often at the start of the month than at the end. In wealthier neighborhoods, the amount stays the same all month. Why do low-income families face more ads in the first week? Because food stamps go out then. Low-income individuals spend 75 percent of their income on ultra-processed food. Ads are just the surface. The real problem is price. When a bottle of water costs more than a can of sugar, we have a crisis. These problems hit hardest for the 140 million Americans who live near poverty. Another trap is distribution. People in some districts, known as food deserts, must drive miles to find vegetables, while ultra-processed food sits around the corner. This is a daily challenge for 23 million Americans. What should we demand from government to fix this? Introduce taxes on sugary drinks. Subsidize farmers so vegetables and fruits become cheaper. Ban the use of food stamps to buy sugary drinks and other junk products. Create incentives to eat well. In Massachusetts, low-income residents who buy fruits and vegetables get a financial bonus. A similar program, Double Up Food Bucks, runs in Michigan, where every $10 from food stamps becomes $20 if the shopper sticks to nutritious, locally grown food. Both consumers and small farmers win, and half the states have already launched similar programs. Install more public water stations. San Francisco has done this, adding 100 water stations across the city. Support and promote initiatives from food desert residents. For example, Ron Finley turns lawns into gardens. The West Oakland community launched People Grocery, a project of mobile stores that deliver vegetables and fruits, inspired by ice cream trucks but stocked with healthy products.',
        wordCount: 284
      },
      {
        title: 'Corporate lobbyists put public health at risk',
        text: 'Many governments are trying to regulate junk food advertising and consumption. In Chile, junk food ads only run on TV at night. Nearly 30 countries tax soft drinks. Many European authorities have introduced simple food labels, green for healthy, yellow for neutral, and red for unhealthy. The American government has tried to follow suit but faces a giant obstacle, the lobbyists of large corporations, who spend enormous sums to influence policy. The cost of loopholes in the Farm Bill is $500 million. Lavish gifts and political campaign funding pave the way for lawmakers loyalty. For instance, Monsanto and Syngenta sponsored three-quarters of the Senate Committee members in charge of nutrition, and after Pepsi donated $5 million, Save the Children backed off the soda taxes campaign. Many lobbyists move freely between industry and government. Maggie Lyons, for example, first pushed the National Grocers Association agenda and later became an adviser to the US Department of Agriculture. The results of lobbying are easy to see. Toxic bisphenol-A, found in kids food, is still legal. Other chemicals are declared safe without testing. There are no labels for GMOs. Governments must change this. The following steps will reduce the damage. Ban officials from lobbying for at least five years after leaving office. Stop former lobbyists from working in government, even as advisers. Make anonymous funding impossible. Tax the sums spent on lobbying. Corporate power is not limited to politics. Although most scientific studies are reliable, it is wise to take their findings with a grain of salt, since companies fund articles, research centers, and universities. For example, the Pennington Biomedical Research Center claims that lack of exercise is the only cause of obesity, and it is no coincidence that the center received an almost $7 million grant from Coca-Cola. Large companies also set up new centers to push ideas that help their sales. Before you trust a claim that sugar is harmless, check who funded the authors or centers. As fake studies mislead communities, the scientific community needs to take the following steps. Scientists should share raw data so others can check the conclusions. Tighten conflict-of-interest rules. Encourage rigorous large trials instead of uncertain observational research.',
        wordCount: 327
      },
      {
        title: 'Healthy soil grows healthy food and a healthier planet',
        text: 'Changing how we use natural resources is no longer optional. 33 percent of topsoil has already vanished in the last 150 years, and studies show the US has only about sixty harvests left before the soil can no longer grow food. On top of that, tilling and pesticides lead to chemical-laden harvests, a stronger greenhouse effect, and weaker soil that absorbs less water. The good news is that we can change it. A 2019 UN report shows that regenerative agriculture can restore the soil, and regenerated soil may contain 3 to 8 percent more organic matter. Each extra percent per acre can hold up to 27,000 gallons of water. The Main Street Project has already adopted regenerative agriculture and shares the experience with other farmers. The idea takes the best of traditional farming and improves it, using no-till methods, rotating crops to keep soil covered, and using grass-fed cattle, since grazing makes roots pump carbon and boosts soil quality. Another positive case is the nonprofit Kiss the Ground, which gives farmers the knowledge and support to use regenerative agriculture. Costa Rica has launched payments for people who help nature through reforestation and water management. The world needs to produce food for up to 10.5 billion people. An indirect way to help soil is to cut waste. Today, we throw away up to 40 percent of our food, which means we waste a huge amount of natural resources. Beyond landfills, food waste produces 8 percent of global methane emissions. San Francisco has set an example by making composting mandatory. In France, grocers who throw out food can face two years in jail. Another good case is the Imperfect Produce initiative, which collects ugly but edible food, like a carrot with two legs, and gives it a chance to reach customers who care. You can cut your own waste by starting a compost pile. Fewer fertilizers also mean less methane and nitrous oxide, and the latter is 300 times more harmful than carbon dioxide.',
        wordCount: 305
      },
      {
        title: 'Closing thoughts',
        text: 'The Congressional Research Service predicted that the cost of health programs will make up almost half of mandatory federal spending in 2025, and that figure is alarming. To avoid this, preventing illness is essential, and healthy food is one of the most effective ways to do it. Experts say that even a 20 percent increase in fruit and vegetable consumption could make a difference, and if Medicare and Medicaid patients follow this advice, the rate of cardiovascular disease could drop by 1.93 million cases. Food is leverage, and by using it, we can tackle many challenges. Soil restoration will bring more nutritious harvests and reduce the greenhouse effect. Lobbying reform will make it easier to pass important laws and force companies to pay for the illnesses their products cause. Subsidy reform will encourage farmers to grow more vegetables and fruits. Bonuses for buying nutritious food with food stamps will let low-income families save on medical costs. A junk food ban will protect our kids mental and physical health. We can move toward these changes by buying healthy products, voting for decent candidates, and supporting nonprofits. Sometimes, sticking to tradition is the best move. In the 1960s, African American diets were full of nutrients, from good fats to fiber, and scientists believe that diet was twice as beneficial as an average one. Our awareness and commitment to a healthy diet will encourage others to follow this wholesome path. Try this. Look at your usual shopping list and choose alternatives to unhealthy products. Check the voting records of politicians and support those who protect your health, not corporate profits. Watch the documentary Broken Brain to discover how food shapes mental health. Read it till the end?',
        wordCount: 282
      }
    ]
  }
};

// Recompute wordCount for each chapter and totalWords
function computeWordCount(text) {
  return text.split(/\s+/).filter(Boolean).length;
}

function recomputeCounts() {
  for (const slug of Object.keys(batch138)) {
    const file = batch138[slug];
    let total = 0;
    for (const ch of file.chapters) {
      ch.wordCount = computeWordCount(ch.text);
      total += ch.wordCount;
    }
    file.totalWords = total;
    file.base = { ...file.base, source: 'rsvp-original', rewrittenAt: Date.now() };
  }
}

recomputeCounts();
